import base64
import json
from typing import Any, Dict

def process_batch_job(event: Dict[str, Any], context: Any) -> None:
    data_b64 = event.get("data")
    if not data_b64:
        print("No data in Pub/Sub message")
        return

    payload = base64.b64decode(data_b64)

    try:
        message = json.loads(payload.decode("utf-8"))
    except (UnicodeDecodeError, json.JSONDecodeError) as exc:
        print(f"Invalid message format: {exc}")
        return

    job_id = message.get("job_id")
    tasks = message.get("tasks", [])
    metadata = message.get("metadata", {})

    print(f"Processing job_id={job_id} task_count={len(tasks)} metadata={metadata}")

    for index, task in enumerate(tasks):
        try:
            task_type = task.get("type")
            task_payload = task.get("payload")
            print(f"Handling task {index} type={task_type} payload={task_payload}")
        except Exception as exc:
            print(f"Task {index} failed: {exc}")

    print(f"Completed job_id={job_id}")